package ui.student;
import javax.swing.*;import javax.swing.table.*;import java.awt.*;import controller.*;import dao.*;import model.*;import util.*;import ui.common.TableStyle;
public class SavedInternshipsPanel extends JPanel{ JTable table=new JTable(); public SavedInternshipsPanel(){ setBackground(UITheme.BG); setLayout(new BorderLayout()); add(UITheme.title("Saved Internships"),BorderLayout.NORTH); add(new JScrollPane(table),BorderLayout.CENTER); load(); } void load(){ Student s=new StudentDAO().getByUserId(Session.getUserId()); DefaultTableModel m=new DefaultTableModel(new Object[]{"Bookmark ID","Internship ID","Saved At"},0); if(s!=null) for(Bookmark b:new BookmarkController().list(s.getId()))m.addRow(new Object[]{b.getId(),b.getJobId(),b.getCreatedAt()}); table.setModel(m); TableStyle.apply(table);} }
